import{_ as t,o as i,c as o,a2 as n}from"./chunks/framework.DGp-bpT-.js";const p=JSON.parse('{"title":"Discord Integration Setup","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/discord-setup.md","filePath":"en/guide/discord-setup.md","lastUpdated":1776065155000}'),s={name:"en/guide/discord-setup.md"};function a(r,e,l,d,h,g){return i(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="discord-integration-setup" tabindex="-1">Discord Integration Setup <a class="header-anchor" href="#discord-integration-setup" aria-label="Permalink to &quot;Discord Integration Setup&quot;">​</a></h1><p>SREBot integration with Discord allows the bot to monitor channel messages, identify Alertmanager notifications, and perform automated AI analysis.</p><hr><h2 id="_1-registering-an-application-in-discord" tabindex="-1">1. Registering an Application in Discord <a class="header-anchor" href="#_1-registering-an-application-in-discord" aria-label="Permalink to &quot;1. Registering an Application in Discord&quot;">​</a></h2><ol><li>Go to the <a href="https://discord.com/developers/applications" target="_blank" rel="noreferrer">Discord Developer Portal</a>.</li><li>Click the <strong>New Application</strong> button.</li><li>Enter a name (e.g., <code>SREBot</code>) and confirm.</li></ol><h2 id="_2-creating-a-bot-and-obtaining-a-token" tabindex="-1">2. Creating a Bot and Obtaining a Token <a class="header-anchor" href="#_2-creating-a-bot-and-obtaining-a-token" aria-label="Permalink to &quot;2. Creating a Bot and Obtaining a Token&quot;">​</a></h2><ol><li>Select <strong>Bot</strong> from the left sidebar.</li><li>Click <strong>Reset Token</strong> (or <strong>Copy Token</strong> if already visible) to get your bot token. <ul><li><strong>Save this token!</strong> In the bot configuration, this is <code>DISCORD_BOT_TOKEN</code>.</li></ul></li><li>Scroll down in the same section to <strong>Privileged Gateway Intents</strong>.</li><li><strong>IMPORTANT</strong>: Enable the <strong>Message Content Intent</strong> toggle. Without this, the bot will not be able to read alert text.</li><li>Click <strong>Save Changes</strong>.</li></ol><h2 id="_3-inviting-the-bot-to-your-server" tabindex="-1">3. Inviting the Bot to Your Server <a class="header-anchor" href="#_3-inviting-the-bot-to-your-server" aria-label="Permalink to &quot;3. Inviting the Bot to Your Server&quot;">​</a></h2><ol><li>Go to <strong>OAuth2 -&gt; URL Generator</strong>.</li><li>Select <code>bot</code> in the <strong>Scopes</strong> list.</li><li>In the <strong>Bot Permissions</strong> list that appears, select: <ul><li><code>Read Messages / View Channels</code></li><li><code>Send Messages</code></li><li><code>Embed Links</code> (recommended)</li><li><code>Read Message History</code></li></ul></li><li>Copy the generated URL at the bottom and open it in your browser.</li><li>Select your server and authorize the bot.</li></ol><h2 id="_4-obtaining-the-channel-id" tabindex="-1">4. Obtaining the Channel ID <a class="header-anchor" href="#_4-obtaining-the-channel-id" aria-label="Permalink to &quot;4. Obtaining the Channel ID&quot;">​</a></h2><ol><li>In Discord, go to <strong>User Settings -&gt; Advanced</strong>.</li><li>Enable <strong>Developer Mode</strong>.</li><li>Right-click the channel where the bot should listen for alerts and select <strong>Copy Channel ID</strong>. <ul><li>This numeric value is <code>DISCORD_CHANNEL_ID</code> in the bot configuration.</li></ul></li></ol><h2 id="_5-bot-configuration-env" tabindex="-1">5. Bot Configuration (Env) <a class="header-anchor" href="#_5-bot-configuration-env" aria-label="Permalink to &quot;5. Bot Configuration (Env)&quot;">​</a></h2><p>Add the collected information to your <code>.env</code> file or Helm chart settings:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Bot token from Discord Developer Portal</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISCORD_BOT_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MTAx...your.token...</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Channel ID (Snowflake ID)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DISCORD_CHANNEL_ID</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">123456789012345678</span></span></code></pre></div><hr><h2 id="how-it-works" tabindex="-1">How it Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it Works&quot;">​</a></h2><ul><li><strong>Automatic Analysis</strong>: Once added to a channel with read permissions, the bot automatically intercepts messages matching Alertmanager patterns and begins its analysis.</li><li><strong>Thread Support</strong>: If alerts are posted in Threads or Forums, the bot will reply within that specific thread.</li><li><strong>Process Indication</strong>: When an alert is received, the bot first sends a <code>🔍 Analyzing...</code> placeholder and then edits it with the full RCA report.</li><li><strong>Status Updates</strong>: If an alert moves to <code>Resolved</code> status, the bot sends a confirmation by replying to the original message.</li></ul><hr><h2 id="summary-required-bot-permissions" tabindex="-1">Summary: Required Bot Permissions <a class="header-anchor" href="#summary-required-bot-permissions" aria-label="Permalink to &quot;Summary: Required Bot Permissions&quot;">​</a></h2><p>For SREBot to function correctly on Discord, the following options must be enabled:</p><p><strong>Developer Portal (Bot Section):</strong></p><ul><li>✅ <strong>Message Content Intent</strong> (under Privileged Gateway Intents)</li></ul><p><strong>Developer Portal (URL Generator):</strong></p><ul><li>✅ <strong>View Channels</strong> (General Permissions)</li><li>✅ <strong>Send Messages</strong> (Text Permissions)</li><li>✅ <strong>Read Message History</strong> (Text Permissions)</li></ul><p><strong>Discord Server Settings (for private channels):</strong> If use in a private channel is required, add the bot to its permissions and grant:</p><ul><li>✅ <strong>View Channel</strong></li><li>✅ <strong>Send Messages</strong></li><li>✅ <strong>Read Message History</strong></li></ul><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Ensure the bot has a role with the <code>Read Message History</code> permission, otherwise it won&#39;t be able to correctly link Resolved notifications to the original alerts.</p></div>`,27)])])}const u=t(s,[["render",a]]);export{p as __pageData,u as default};
